package com.v2ray.ang.dtoimport com.google.gson.annotations.SerializedNamedata class VersionInfo(    @SerializedName("versionCode")    val versionCode: Int,    @SerializedName("minVersionCode")    val minVersionCode: Int,    @SerializedName("versionName")    val versionName: String,    @SerializedName("downloadUrl")    val downloadUrl: String,    @SerializedName("releaseNotes")    val releaseNotes: String)